from __future__ import annotations

from pathlib import Path
from types import TracebackType
from typing import (
    Iterator,
    Union,
    Type,
    Dict,
    NamedTuple,
    Iterable,
    BinaryIO,
    cast,
    overload,
)

from geosat.tools.urlprotocol import UrlProtocols, UrlReader, UrlWriter, UrlContext
from laspy import LasHeader
from typing_extensions import Literal, Buffer

from . import las
from .. import PointCloud
from ..pointcloud import PathLike, Reader, Writer


class CloudIO(NamedTuple):
    reader: Type[Reader]
    writer: Type[Writer]


KNOWN_FORMATS: Dict[str, CloudIO] = {
    ".las": CloudIO(las.LasReader, las.LasWriter),
    ".laz": CloudIO(las.LazReader, las.LazWriter),
}


def _reader_class_for_path(
    path: PathLike,
) -> Type[Reader]:
    """returns the reader type to use for the extension of the file path"""
    try:
        return KNOWN_FORMATS[Path(path).suffix].reader
    except KeyError as ex:
        raise KeyError(f"Unhandled format '{ex}'") from ex


def _writer_class_for_path(
    path: PathLike,
) -> Type[Writer]:
    """returns the writer type to use for the extension of the file path"""
    try:
        return KNOWN_FORMATS[Path(path).suffix].writer
    except KeyError as ex:
        raise KeyError(f"Unhandled format '{ex}'") from ex


class UrlContextAdapter(BinaryIO):
    """A wrapper to make UrlWriter or UrlReader act like a file-object"""

    def __init__(self, urlcontext: UrlContext) -> None:
        self.urlcontext = urlcontext
        self.stream = self.urlcontext.__enter__()

    def write(self, s: Buffer) -> int:
        return self.stream.write(s)

    def seek(self, offset: int, whence: int = 0) -> int:
        return self.stream.seek(offset, whence)

    def read(self, n: int = -1) -> bytes:
        return self.stream.read(n)

    def tell(self) -> int:
        return self.stream.tell()

    def flush(self) -> None:
        return self.stream.flush()

    def close(self) -> None:
        return self.urlcontext.__exit__(None, None, None)

    def fileno(self) -> int:
        raise NotImplementedError

    def isatty(self) -> bool:
        raise NotImplementedError

    def readable(self) -> bool:
        raise NotImplementedError

    def readline(self, limit: int = ...) -> bytes:
        raise NotImplementedError

    def readlines(self, hint: int = ...) -> list[bytes]:
        raise NotImplementedError

    def seekable(self) -> bool:
        return self.stream.seekable()

    def truncate(self, size: int | None = ...) -> int:
        raise NotImplementedError

    def writable(self) -> bool:
        raise NotImplementedError

    def writelines(self, lines: Iterable[Union[bytes, Buffer]]) -> None:
        raise NotImplementedError

    def __next__(self) -> bytes:
        raise NotImplementedError

    def __iter__(self) -> Iterator[bytes]:
        raise NotImplementedError

    def __enter__(self) -> BinaryIO:
        raise NotImplementedError

    def __exit__(
        self,
        t: Type[BaseException] | None,
        value: BaseException | None,
        traceback: TracebackType | None,
    ) -> None:
        raise NotImplementedError


@overload
def open_path(path: PathLike, mode: Literal["r"] = "r") -> Reader: ...


@overload
def open_path(path: PathLike, mode: Literal["w"]) -> Writer: ...


def open_path(path: PathLike, mode: Literal["r", "w"] = "r") -> Union[Reader, Writer]:
    """opens a file and returns the Reader or Writer
    for it.

    :param path: path to the file to be opened
    :param mode: "r" for reading, "w" for writing
    :return:
    """
    if mode == "r":
        file_obj = UrlContextAdapter(UrlReader(str(path), UrlProtocols()))
        return _reader_class_for_path(path).from_source(file_obj)
    elif mode == "w":
        file_obj = UrlContextAdapter(UrlWriter(str(path), UrlProtocols()))
        return _writer_class_for_path(path).from_dest(file_obj)
    else:
        raise ValueError(f"Invalid mode {mode}")


def read_from_path(path: PathLike) -> PointCloud:
    """Reads the whole point cloud stored in the file pointed by path"""
    with open_path(path, mode="r") as reader:
        reader = cast(Reader, reader)
        point_cloud = reader.read()

    point_cloud.metadata["filepath"] = str(path)
    return point_cloud


def read_only_header_from_path(path: PathLike) -> LasHeader:
    """Reads the whole point cloud stored in the file pointed by path"""
    with open_path(path, mode="r") as reader:
        reader = cast(Reader, reader)
        header = reader.header()
    return header


def write_to_path(path: PathLike, point_cloud: PointCloud) -> None:
    """Writes the whole point cloud to a new file."""
    with open_path(path, mode="w") as writer:
        writer = cast(Writer, writer)
        writer.write(point_cloud)


class ChunkedReader:
    """A class that wraps another reader (see :meth:`.open_path`)
    to allow reading the file chunk by chunk.
    """

    def __init__(self, actual_reader: Reader, chunk_size: int):
        """
        :param actual_reader: The reader to be wrapped eg LasReader
        :param chunk_size: how many points to request each time
        """
        self.reader = actual_reader
        self.chunk_size = chunk_size

    def __iter__(self) -> Iterator[PointCloud]:
        while True:
            point_cloud = self.reader.read(self.chunk_size)
            if not point_cloud:
                return
            yield point_cloud
